// Test to verify the issue with delay(Duration) losing sub-millisecond precision
@Test
fun testDelayDurationAccuracy() = runTest {
    withContext(Dispatchers.Default) {
        repeat(10) {
            val expectedDuration = 998.milliseconds + 902752.nanoseconds
            val actualDuration = measureTime {
                delay(expectedDuration)
            }
            val difference = actualDuration - expectedDuration
            // The difference should be positive (actual >= expected)
            // This will fail with the current implementation
            assertTrue(difference.isPositive(), "Delay was shorter than expected. Difference: $difference")
        }
    }
}

@Test
fun testToDelayMillis_RoundsUp() {
    // Test that durations with sub-milliseconds are rounded up
    val testCases = listOf(
        1.milliseconds to 1L,
        1.5.milliseconds to 2L,
        0.001.milliseconds to 1L, // 1 microsecond
        0.999.milliseconds to 1L,
        998.75909.milliseconds to 999L,
        998.milliseconds to 998L,
        999.milliseconds + 999999.nanoseconds to 1000L,
        1000.milliseconds to 1000L,
    )

    for ((duration, expectedMillis) in testCases) {
        val actual = duration.toDelayMillis()
        assertEquals(expectedMillis, actual, "Duration $duration should convert to $expectedMillis ms but got $actual ms")
    }
}
