package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds
import kotlin.time.Duration.Companion.microseconds

class DelayDurationPrecisionTest : TestBase() {

    @Test
    fun testToDelayMillis_RoundsUpMicroseconds() {
        // Test that durations with microseconds are rounded up
        testToDelayMillis(1.milliseconds, 1L)
        testToDelayMillis(1.milliseconds + 1.microseconds, 2L)
        testToDelayMillis(1.milliseconds + 500.microseconds, 2L)
        testToDelayMillis(1.milliseconds + 999.microseconds, 2L)
    }

    @Test
    fun testToDelayMillis_RoundsUpNanoseconds() {
        // Test that durations with nanoseconds are rounded up
        testToDelayMillis(1.milliseconds, 1L)
        testToDelayMillis(1.milliseconds + 1.nanoseconds, 2L)
        testToDelayMillis(1.milliseconds + 500.nanoseconds, 2L)
        testToDelayMillis(1.milliseconds + 999999.nanoseconds, 2L)
    }

    @Test
    fun testToDelayMillis_LargeDurations() {
        // Test with the issue example
        testToDelayMillis(998.75909.milliseconds, 999L)
        testToDelayMillis(998.milliseconds + 902752.nanoseconds, 999L)
        testToDelayMillis(999.milliseconds + 999999.nanoseconds, 1000L)
    }

    @Test
    fun testToDelayMillis_ZeroAndNegative() {
        // Edge cases
        testToDelayMillis(Duration.ZERO, 0L)
        testToDelayMillis((-1).nanoseconds, 0L)
        testToDelayMillis((-1).milliseconds, 0L)
    }

    @Test
    fun testToDelayMillis_SubMillisecondOnly() {
        // Test durations less than 1 millisecond should be coerced to at least 1ms
        testToDelayMillis(0.1.milliseconds, 1L)
        testToDelayMillis(0.5.milliseconds, 1L)
        testToDelayMillis(0.999.milliseconds, 1L)
        testToDelayMillis(1.microseconds, 1L)
        testToDelayMillis(500.microseconds, 1L)
        testToDelayMillis(999.microseconds, 1L)
        testToDelayMillis(1.nanoseconds, 1L)
    }

    @Test
    fun testDelayWithSubMillisecondPrecision() = runTest {
        // Test that delay with sub-millisecond duration doesn't sleep less than requested
        val testDurations = listOf(
            1.milliseconds + 500.microseconds,
            5.milliseconds + 750.nanoseconds,
            10.milliseconds + 999.microseconds
        )

        for (duration in testDurations) {
            val expectedMillis = duration.toDelayMillis()
            val startTime = System.nanoTime()
            delay(duration)
            val actualNanos = System.nanoTime() - startTime
            val actualMillis = actualNanos / 1_000_000

            // The actual delay should be at least the rounded-up millisecond value
            // Note: Due to scheduling precision, it might be slightly longer, but never shorter
            assertTrue(actualMillis >= expectedMillis,
                "Expected delay of at least $expectedMillis ms, but got $actualMillis ms for duration $duration")
        }
    }

    @Test
    fun testDelayExactMilliseconds() = runTest {
        // Test that exact milliseconds still work correctly
        val testDurations = listOf(
            1.milliseconds,
            10.milliseconds,
            100.milliseconds,
            1000.milliseconds
        )

        for (duration in testDurations) {
            val expectedMillis = duration.toDelayMillis()
            val startTime = System.nanoTime()
            delay(duration)
            val actualNanos = System.nanoTime() - startTime
            val actualMillis = actualNanos / 1_000_000

            assertTrue(actualMillis >= expectedMillis,
                "Expected delay of at least $expectedMillis ms, but got $actualMillis ms for duration $duration")
        }
    }

    private fun testToDelayMillis(duration: Duration, expected: Long) {
        val actual = duration.toDelayMillis()
        assertEquals(expected, actual,
            "Duration $duration should convert to $expected ms but got $actual ms")
    }
}
"}

